// Skill usage tracker — AB-4.
//
// Maintains `skill-usage.json` inside ${MEMORY_DIR}/config/ so that
// usage counts are shared across all agent CLIs (Kiro / Claude / Codex).
// Previously stored as `.usage.json` inside ${SKILL_DIR}; on first run
// the old file is auto-migrated if the new one doesn't exist yet.
// Schema documented in docs/ab-token-protocol.md §6.1.
//
// Responsibilities:
//   • migrateFromDisk() — on first run (and occasionally thereafter),
//     scan ${SKILL_DIR}/*/SKILL.md, create entries for skills not yet
//     tracked, and flag entries whose SKILL.md has disappeared.
//   • markListed(name) — bump `last_bridge_listed_at`; used when
//     /skillusage displays the skill in bridge output.
//   • markUsed(name, reason) — called by observerTransformer when it
//     extracts a <<SKILL_USED:name|reason>> token. Updates
//     `last_agent_used_at`, `last_reason`, `use_count++`. Creates an
//     orphan entry if `name` has no SKILL.md on disk.
//   • setPinned(name, pinned) — flip the `pinned` flag.
//   • listAll() — read-only snapshot for the /skillusage handler.
//
// Concurrency: every mutation goes through atomicJson.updateJson(),
// which serializes read-modify-write per file path in-process. Single
// bridge process assumption — see atomicJson.ts §not-a-goal for the
// multi-process caveat.

import { readdir, stat } from "node:fs/promises";
import path from "node:path";
import { existsSync } from "node:fs";
import {
  atomicWriteJson,
  readJsonOrDefault,
  updateJson,
} from "./atomicJson.js";
import { config } from "./config.js";

/** Per-skill entry. Keep fields aligned with docs/ab-token-protocol.md §6.1. */
export interface UsageEntry {
  created_at: string;            // ISO, first time bridge saw this skill
  last_bridge_listed_at: string | null;
  last_agent_used_at: string | null;
  use_count: number;
  last_reason: string | null;
  pinned: boolean;
  notes: string | null;
  orphan: boolean;
}

/** File contents. */
export interface UsageJson {
  _schema_version: 1;
  _last_updated_at: string | null;
  skills: Record<string, UsageEntry>;
}

/** Factory for a blank schema. */
function emptyUsageJson(): UsageJson {
  return {
    _schema_version: 1,
    _last_updated_at: null,
    skills: {},
  };
}

/** Factory for a fresh entry. created_at is caller-supplied so migration
 * can back-date using the SKILL.md mtime. */
function newEntry(createdAt: string, orphan = false): UsageEntry {
  return {
    created_at: createdAt,
    last_bridge_listed_at: null,
    last_agent_used_at: null,
    use_count: 0,
    last_reason: null,
    pinned: false,
    notes: null,
    orphan,
  };
}

function nowIso(): string {
  return new Date().toISOString();
}

/** Full path to the centralized usage file (MEMORY_DIR/config/skill-usage.json).
 * The skillDir param is kept for backward compat but ignored for path resolution. */
export function usageFilePath(_skillDir?: string): string {
  return path.join(config.memoryDir, "config", "skill-usage.json");
}

/** Legacy path — old location inside SKILL_DIR. Used for one-time migration. */
function legacyUsageFilePath(skillDir: string): string {
  return path.join(skillDir, ".usage.json");
}

/** One-time migration: if new location doesn't exist but old one does,
 * copy old → new. Merges if both exist (new wins on conflict). */
export async function migrateUsageFileIfNeeded(skillDir: string): Promise<boolean> {
  const newPath = usageFilePath();
  const oldPath = legacyUsageFilePath(skillDir);
  if (existsSync(newPath) || !existsSync(oldPath)) return false;

  // Old exists, new doesn't — read old and write to new location
  const oldData = await readJsonOrDefault<UsageJson>(oldPath, emptyUsageJson);
  const { mkdirSync } = await import("node:fs");
  mkdirSync(path.dirname(newPath), { recursive: true });
  await atomicWriteJson(newPath, oldData);
  console.log(`[usageStore] Migrated .usage.json from ${oldPath} → ${newPath}`);
  return true;
}

// ───────────────────────────────────────────────────────────────────────
// Disk scan — discover skills by reading SKILL_DIR
// ───────────────────────────────────────────────────────────────────────

/** A skill lives at `${SKILL_DIR}/<name>/SKILL.md`. Return the list of
 * names and their SKILL.md mtimes, sorted by name. Hidden dirs (dot-
 * prefix, `.archive/`, etc.) are skipped. Missing SKILL_DIR → []. */
export async function scanSkillDir(
  skillDir: string,
): Promise<Array<{ name: string; mtime: Date }>> {
  let entries: string[];
  try {
    entries = await readdir(skillDir);
  } catch (err: any) {
    if (err?.code === "ENOENT") return [];
    throw err;
  }
  const found: Array<{ name: string; mtime: Date }> = [];
  for (const e of entries) {
    if (e.startsWith(".")) continue;
    const skillMdPath = path.join(skillDir, e, "SKILL.md");
    try {
      const st = await stat(skillMdPath);
      if (st.isFile()) {
        found.push({ name: e, mtime: st.mtime });
      }
    } catch {
      // No SKILL.md in this dir — not a skill, skip silently.
    }
  }
  found.sort((a, b) => a.name.localeCompare(b.name));
  return found;
}

// ───────────────────────────────────────────────────────────────────────
// CRUD
// ───────────────────────────────────────────────────────────────────────

/** Read-only snapshot. Returns the full UsageJson, creating an empty one
 * if the file doesn't exist (without writing). */
export async function listAll(skillDir: string): Promise<UsageJson> {
  return readJsonOrDefault<UsageJson>(
    usageFilePath(),
    emptyUsageJson,
  );
}

/** Ensure each skill on disk has an entry, and mark any entry whose
 * SKILL.md has disappeared as `orphan: true`. Does NOT remove orphan
 * entries — that's a user-driven decision (the /skillusage output
 * flags them so the user can `/pin` or clean up manually).
 *
 * Returns a summary for logging: added names, newly-orphaned names,
 * de-orphaned names (SKILL.md reappeared). */
export async function migrateFromDisk(
  skillDir: string,
): Promise<{
  added: string[];
  newlyOrphaned: string[];
  deOrphaned: string[];
}> {
  // One-time migration from old SKILL_DIR/.usage.json to MEMORY_DIR/config/
  await migrateUsageFileIfNeeded(skillDir);

  const diskList = await scanSkillDir(skillDir);
  const diskByName = new Map<string, Date>();
  for (const s of diskList) diskByName.set(s.name, s.mtime);

  const added: string[] = [];
  const newlyOrphaned: string[] = [];
  const deOrphaned: string[] = [];

  await updateJson<UsageJson>(
    usageFilePath(),
    emptyUsageJson,
    (current) => {
      const next: UsageJson = {
        ...current,
        _last_updated_at: nowIso(),
        skills: { ...current.skills },
      };
      // Add entries for new skills
      for (const { name, mtime } of diskList) {
        if (!(name in next.skills)) {
          next.skills[name] = newEntry(mtime.toISOString(), false);
          added.push(name);
        } else if (next.skills[name].orphan) {
          next.skills[name] = { ...next.skills[name], orphan: false };
          deOrphaned.push(name);
        }
      }
      // Flag entries whose SKILL.md no longer exists.
      for (const name of Object.keys(next.skills)) {
        if (!diskByName.has(name) && !next.skills[name].orphan) {
          next.skills[name] = { ...next.skills[name], orphan: true };
          newlyOrphaned.push(name);
        }
      }
      return next;
    },
  );

  return { added, newlyOrphaned, deOrphaned };
}

/** Record that the bridge listed this skill to the user (e.g. via
 * /skillusage). Creates an orphan entry if `name` isn't on disk. */
export async function markListed(
  skillDir: string,
  name: string,
): Promise<void> {
  const ts = nowIso();
  await updateJson<UsageJson>(
    usageFilePath(),
    emptyUsageJson,
    (current) => {
      const next: UsageJson = {
        ...current,
        _last_updated_at: ts,
        skills: { ...current.skills },
      };
      const existing = next.skills[name];
      if (existing) {
        next.skills[name] = { ...existing, last_bridge_listed_at: ts };
      } else {
        next.skills[name] = {
          ...newEntry(ts, /* orphan */ true),
          last_bridge_listed_at: ts,
        };
      }
      return next;
    },
  );
}

/** Record that the agent used this skill (from a <<SKILL_USED>> token).
 * Creates an orphan entry if `name` isn't on disk. */
export async function markUsed(
  skillDir: string,
  name: string,
  reason: string,
): Promise<void> {
  const ts = nowIso();
  // Detect orphan at write time. We do one `stat` per call — cheap and
  // avoids stale in-memory caches disagreeing with disk.
  let diskExists = false;
  try {
    const st = await stat(path.join(skillDir, name, "SKILL.md"));
    diskExists = st.isFile();
  } catch {
    diskExists = false;
  }

  await updateJson<UsageJson>(
    usageFilePath(),
    emptyUsageJson,
    (current) => {
      const next: UsageJson = {
        ...current,
        _last_updated_at: ts,
        skills: { ...current.skills },
      };
      const existing = next.skills[name];
      if (existing) {
        next.skills[name] = {
          ...existing,
          last_agent_used_at: ts,
          last_reason: reason,
          use_count: existing.use_count + 1,
          // Transition in/out of orphan state based on current disk.
          orphan: !diskExists,
        };
      } else {
        next.skills[name] = {
          ...newEntry(ts, !diskExists),
          last_agent_used_at: ts,
          last_reason: reason,
          use_count: 1,
        };
      }
      return next;
    },
  );
}

/** Flip the pinned flag for an existing entry. If the name has no entry
 * yet (never listed, never used), we create a stub so the flag persists. */
export async function setPinned(
  skillDir: string,
  name: string,
  pinned: boolean,
): Promise<void> {
  const ts = nowIso();
  await updateJson<UsageJson>(
    usageFilePath(),
    emptyUsageJson,
    (current) => {
      const next: UsageJson = {
        ...current,
        _last_updated_at: ts,
        skills: { ...current.skills },
      };
      const existing = next.skills[name];
      if (existing) {
        next.skills[name] = { ...existing, pinned };
      } else {
        next.skills[name] = { ...newEntry(ts, /* orphan */ true), pinned };
      }
      return next;
    },
  );
}

/** Convenience: does this skill have `pinned: true`? Returns false if
 * no entry exists yet. */
export async function isPinned(
  skillDir: string,
  name: string,
): Promise<boolean> {
  const all = await listAll(skillDir);
  return all.skills[name]?.pinned === true;
}

// ───────────────────────────────────────────────────────────────────────
// Re-export for tests / advanced callers
// ───────────────────────────────────────────────────────────────────────
export { atomicWriteJson, emptyUsageJson };

