   324→/** Convenience: does this skill have `pinned: true`? Returns false if
   325→ * no entry exists yet. */
   326→export async function isPinned(
   327→  skillDir: string,
   328→  name: string,
   329→): Promise<boolean> {
   330→  const all = await listAll(skillDir);
   331→  return all.skills[name]?.pinned === true;
   332→}
   333→
   334→// ───────────────────────────────────────────────────────────────────────
   335→// Re-export for tests / advanced callers
   336→// ───────────────────────────────────────────────────────────────────────
   337→export { atomicWriteJson, emptyUsageJson };
   338→

