// AB-4 smoke: usageStore behavior.
//
// Sets up a temp SKILL_DIR with 3 fake skill folders, each containing a
// SKILL.md. Exercises migrate/markListed/markUsed/setPinned/orphan
// transitions. Uses compiled dist/usageStore.js so the smoke reflects
// what the bridge will actually load.
//
// Run: node scripts/check-usage-store.mjs

import { mkdir, rm, utimes, writeFile, readFile, stat } from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";
import {
  listAll,
  markListed,
  markUsed,
  migrateFromDisk,
  setPinned,
  isPinned,
  scanSkillDir,
  usageFilePath,
} from "../dist/usageStore.js";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const tmpDir = path.join(__dirname, "..", "tmp", "check-usage-store");

async function fresh() {
  await rm(tmpDir, { recursive: true, force: true });
  await mkdir(tmpDir, { recursive: true });
}

/** Create a fake skill folder with a SKILL.md, optionally setting mtime. */
async function makeFakeSkill(skillDir, name, content = "# stub", mtime = null) {
  const dir = path.join(skillDir, name);
  await mkdir(dir, { recursive: true });
  const filePath = path.join(dir, "SKILL.md");
  await writeFile(filePath, content, "utf8");
  if (mtime) await utimes(filePath, mtime, mtime);
}

const results = [];
function ok(name) {
  results.push({ name, pass: true });
  console.log(`[PASS] ${name}`);
}
function fail(name, detail) {
  results.push({ name, pass: false, detail });
  console.error(`[FAIL] ${name}: ${detail}`);
}

// ───────────────────────────────────────────────────────────────────────
// 1. scanSkillDir: ENOENT → []
// ───────────────────────────────────────────────────────────────────────
await fresh();
{
  const skillDir = path.join(tmpDir, "does-not-exist");
  const out = await scanSkillDir(skillDir);
  if (Array.isArray(out) && out.length === 0) ok("1. scanSkillDir ENOENT → []");
  else fail("1. scanSkillDir ENOENT → []", JSON.stringify(out));
}

// ───────────────────────────────────────────────────────────────────────
// 2. scanSkillDir: skips hidden dirs, collects SKILL.md-bearing folders
// ───────────────────────────────────────────────────────────────────────
{
  const skillDir = path.join(tmpDir, "s2");
  await mkdir(skillDir, { recursive: true });
  await makeFakeSkill(skillDir, "alpha");
  await makeFakeSkill(skillDir, "beta");
  await mkdir(path.join(skillDir, "not-a-skill-no-md"), { recursive: true });
  await mkdir(path.join(skillDir, ".hidden"), { recursive: true });
  await writeFile(path.join(skillDir, ".hidden", "SKILL.md"), "# hidden", "utf8");
  const out = await scanSkillDir(skillDir);
  const names = out.map((s) => s.name).sort();
  if (JSON.stringify(names) === JSON.stringify(["alpha", "beta"])) {
    ok("2. scanSkillDir skips hidden + folders without SKILL.md");
  } else {
    fail("2. scanSkillDir skips hidden + folders without SKILL.md", names.join(","));
  }
}

// ───────────────────────────────────────────────────────────────────────
// 3. migrateFromDisk: creates entries for all skills with SKILL.md mtime
// ───────────────────────────────────────────────────────────────────────
{
  const skillDir = path.join(tmpDir, "s3");
  await mkdir(skillDir, { recursive: true });
  const ancient = new Date("2024-01-15T10:00:00Z");
  await makeFakeSkill(skillDir, "one", "one", ancient);
  await makeFakeSkill(skillDir, "two", "two");
  const summary = await migrateFromDisk(skillDir);
  const all = await listAll(skillDir);
  const pass =
    summary.added.length === 2 &&
    summary.added.includes("one") &&
    summary.added.includes("two") &&
    all.skills.one &&
    all.skills.one.created_at === ancient.toISOString() &&
    all.skills.one.pinned === false &&
    all.skills.one.use_count === 0 &&
    all.skills.two.created_at.length > 10;
  if (pass) ok("3. migrateFromDisk seeds entries using SKILL.md mtime");
  else fail("3. migrateFromDisk seeds entries using SKILL.md mtime",
    JSON.stringify({ summary, skills: all.skills }));
}

// ───────────────────────────────────────────────────────────────────────
// 4. migrateFromDisk: idempotent — second call adds nothing
// ───────────────────────────────────────────────────────────────────────
{
  const skillDir = path.join(tmpDir, "s4");
  await mkdir(skillDir, { recursive: true });
  await makeFakeSkill(skillDir, "only");
  await migrateFromDisk(skillDir);
  const summary2 = await migrateFromDisk(skillDir);
  if (summary2.added.length === 0 && summary2.newlyOrphaned.length === 0 &&
      summary2.deOrphaned.length === 0) {
    ok("4. migrateFromDisk idempotent on second call");
  } else {
    fail("4. migrateFromDisk idempotent on second call", JSON.stringify(summary2));
  }
}

// ───────────────────────────────────────────────────────────────────────
// 5. migrateFromDisk: SKILL.md disappears → entry marked orphan
// ───────────────────────────────────────────────────────────────────────
{
  const skillDir = path.join(tmpDir, "s5");
  await mkdir(skillDir, { recursive: true });
  await makeFakeSkill(skillDir, "gone-soon");
  await migrateFromDisk(skillDir);
  // Remove the SKILL.md
  await rm(path.join(skillDir, "gone-soon"), { recursive: true, force: true });
  const summary = await migrateFromDisk(skillDir);
  const all = await listAll(skillDir);
  if (summary.newlyOrphaned.includes("gone-soon") &&
      all.skills["gone-soon"].orphan === true) {
    ok("5. missing SKILL.md flagged as orphan");
  } else {
    fail("5. missing SKILL.md flagged as orphan",
      JSON.stringify({ summary, entry: all.skills["gone-soon"] }));
  }
}

// ───────────────────────────────────────────────────────────────────────
// 6. migrateFromDisk: SKILL.md reappears → orphan flag cleared
// ───────────────────────────────────────────────────────────────────────
{
  const skillDir = path.join(tmpDir, "s6");
  await mkdir(skillDir, { recursive: true });
  await makeFakeSkill(skillDir, "returns");
  await migrateFromDisk(skillDir);
  await rm(path.join(skillDir, "returns"), { recursive: true, force: true });
  await migrateFromDisk(skillDir);
  await makeFakeSkill(skillDir, "returns");
  const summary = await migrateFromDisk(skillDir);
  const all = await listAll(skillDir);
  if (summary.deOrphaned.includes("returns") &&
      all.skills.returns.orphan === false) {
    ok("6. reappearing SKILL.md clears orphan flag");
  } else {
    fail("6. reappearing SKILL.md clears orphan flag",
      JSON.stringify({ summary, entry: all.skills.returns }));
  }
}

// ───────────────────────────────────────────────────────────────────────
// 7. markUsed increments use_count and records last_reason
// ───────────────────────────────────────────────────────────────────────
{
  const skillDir = path.join(tmpDir, "s7");
  await mkdir(skillDir, { recursive: true });
  await makeFakeSkill(skillDir, "alpha");
  await migrateFromDisk(skillDir);
  await markUsed(skillDir, "alpha", "first use");
  await markUsed(skillDir, "alpha", "second use");
  await markUsed(skillDir, "alpha", "third use");
  const all = await listAll(skillDir);
  const e = all.skills.alpha;
  if (e.use_count === 3 && e.last_reason === "third use" &&
      e.last_agent_used_at !== null) {
    ok("7. markUsed increments count and updates reason");
  } else {
    fail("7. markUsed increments count and updates reason", JSON.stringify(e));
  }
}

// ───────────────────────────────────────────────────────────────────────
// 8. markUsed on unknown name creates orphan entry
// ───────────────────────────────────────────────────────────────────────
{
  const skillDir = path.join(tmpDir, "s8");
  await mkdir(skillDir, { recursive: true });
  await markUsed(skillDir, "never-existed", "agent hallucinated a name");
  const all = await listAll(skillDir);
  const e = all.skills["never-existed"];
  if (e && e.orphan === true && e.use_count === 1) {
    ok("8. markUsed creates orphan entry for unknown name");
  } else {
    fail("8. markUsed creates orphan entry for unknown name", JSON.stringify(e));
  }
}

// ───────────────────────────────────────────────────────────────────────
// 9. markListed updates last_bridge_listed_at
// ───────────────────────────────────────────────────────────────────────
{
  const skillDir = path.join(tmpDir, "s9");
  await mkdir(skillDir, { recursive: true });
  await makeFakeSkill(skillDir, "alpha");
  await migrateFromDisk(skillDir);
  const beforeTime = Date.now();
  await markListed(skillDir, "alpha");
  const all = await listAll(skillDir);
  const ts = Date.parse(all.skills.alpha.last_bridge_listed_at);
  if (ts >= beforeTime && ts <= Date.now()) {
    ok("9. markListed sets last_bridge_listed_at");
  } else {
    fail("9. markListed sets last_bridge_listed_at",
      `ts=${ts} range=[${beforeTime},${Date.now()}]`);
  }
}

// ───────────────────────────────────────────────────────────────────────
// 10. setPinned / isPinned round-trip
// ───────────────────────────────────────────────────────────────────────
{
  const skillDir = path.join(tmpDir, "s10");
  await mkdir(skillDir, { recursive: true });
