import { mkdir, rm, utimes, writeFile, readFile, stat } from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const tmpDir = path.join(__dirname, "..", "tmp", "check-usage-store");

// ⚠️ usageStore 的 store 路徑由 config.memoryDir（MEMORY_DIR env）決定，
