toolResponse.originalFile:
// AB-6 smoke: integration between observerTransformer + goalStore +
// usageStore. Simulates the end-to-end token-to-store flow without
// loading the full bot.
//
// What this does NOT test: real slash-command ctx dispatch (requires a
// mocked grammY Context). handlePin/handleSkillUsage/handleGoal each
// call store APIs we've already unit-tested — the smoke here covers
// the **observer → store** glue that AB-7 will rely on.
//
// Run: node scripts/check-ab6-integration.mjs

import { mkdir, rm, writeFile } from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const tmpRoot = path.join(__dirname, "..", "tmp", "check-ab6-integration");
const memoryDir = path.join(tmpRoot, "memory");
const skillDir = path.join(tmpRoot, "skills");

// ⚠️ usageStore 的 store 路徑由 config.memoryDir（MEMORY_DIR env）決定，
// 與 skillDir 參數無關。必須在 import dist 模組**之前**把 MEMORY_DIR 指到
// temp 目錄，否則 skill-alpha/skill-phantom 等 fixture 會寫進生產 store
//（2026-07-07 生產 store 汙染事故的根因）。靜態 import 會 hoist，必須用
// 動態 import；dotenv 不會覆蓋已存在的 env var。
process.env.MEMORY_DIR = memoryDir;

const { transform } = await import("../dist/observerTransformer.js");
const goalStore = await import("../dist/goalStore.js");
const usageStore = await import("../dist/usageStore.js");

async function fresh() {
  await rm(tmpRoot, { recursive: true, force: true });
  await mkdir(memoryDir, { recursive: true });
  await mkdir(skillDir, { recursive: true });
  // Seed with three fake skills so SKILL_USED has something to hit.
  for (const name of ["skill-alpha", "skill-beta", "skill-gamma"]) {
    await mkdir(path.join(skillDir, name), { recursive: true });
    await writeFile(path.join(skillDir, name, "SKILL.md"), `# ${name}`, "utf8");
  }
  await usageStore.migrateFromDisk(skillDir);
}

const results = [];
function ok(name) {
  results.push({ name, pass: true });
  console.log(`[PASS] ${name}`);
}
function fail(name, detail) {
  results.push({ name, pass: false, detail });
  console.error(`[FAIL] ${name}: ${detail}`);
}

// ───────────────────────────────────────────────────────────────────────
// Simulated observer: takes agent reply, runs transform(), dispatches
// SKILL_USED → usageStore.markUsed and GOAL_DONE → goalStore.markDone.
// This is the exact pattern AB-7 will wire into index.ts's reply path.
// ───────────────────────────────────────────────────────────────────────
async function simulateObserver(chatId, reply) {
  const r = transform(reply);
  for (const u of r.skillUsages) {
    await usageStore.markUsed(skillDir, u.name, u.reason);
  }
  if (r.goalDone) {
    const active = await goalStore.isActive(memoryDir, chatId);
    if (active) {
      await goalStore.markDone(memoryDir, chatId, r.goalDone.reason);
    } else {
      // AB-1 §1.1: "Token appears, goal not active → strip token, log warn"
      console.warn(`[observer] GOAL_DONE ignored: no active goal for chat ${chatId}`);
    }
  }
  return {
    displayText: r.text,
    skillUsages: r.skillUsages,
    goalDone: r.goalDone,
  };
}

// ───────────────────────────────────────────────────────────────────────
// 1. Agent reply with SKILL_USED → usageStore.use_count++
// ───────────────────────────────────────────────────────────────────────
await fresh();
{
  const reply =
    "I used this skill.\n" +
    "<<SKILL_USED:skill-alpha|consulted the frontmatter section>>\n" +
    "Done.";
  const out = await simulateObserver(1001, reply);
  const usage = await usageStore.listAll(skillDir);
  const alpha = usage.skills["skill-alpha"];
  if (out.displayText.includes("I used this skill.") &&
      out.displayText.includes("Done.") &&
      alpha.use_count === 1 &&
      alpha.last_reason === "consulted the frontmatter section" &&
      !out.displayText.includes("SKILL_USED")) {
    ok("1. SKILL_USED stripped + usageStore updated");
  } else {
    fail("1. SKILL_USED stripped + usageStore updated",
      JSON.stringify({ text: out.displayText, alpha }));
  }
}

// ───────────────────────────────────────────────────────────────────────
// 2. GOAL_DONE with active goal → marks done + strips token
// ───────────────────────────────────────────────────────────────────────
{
  const chatId = 2002;
  await goalStore.set(memoryDir, chatId, "sample task", { maxTurns: 5 });
  const out = await simulateObserver(
    chatId,
    "Finished everything.\n<<GOAL_DONE:all four files created>>",
  );
  const s = await goalStore.get(memoryDir, chatId);
  if (s?.status === "done" &&
      s.last_reason === "all four files created" &&
      out.displayText === "Finished everything." &&
      out.goalDone?.reason === "all four files created") {
    ok("2. GOAL_DONE with active goal → done + stripped");
  } else {
    fail("2. GOAL_DONE with active goal → done + stripped",
      JSON.stringify({ state: s, out }));
  }
}

// ───────────────────────────────────────────────────────────────────────
// 3. GOAL_DONE without active goal → token stripped, warn logged, no state change
// ───────────────────────────────────────────────────────────────────────
{
  const chatId = 3003;
  const out = await simulateObserver(
    chatId,
    "Hello <<GOAL_DONE:nothing was set>>",
  );
  const s = await goalStore.get(memoryDir, chatId);
  if (s === null &&
      out.goalDone?.reason === "nothing was set" &&
      !out.displayText.includes("GOAL_DONE")) {
    ok("3. GOAL_DONE without active goal → stripped, no store change");
  } else {
    fail("3. GOAL_DONE without active goal → stripped, no store change",
      JSON.stringify({ state: s, out }));
  }
}

// ───────────────────────────────────────────────────────────────────────
// 4. Multiple SKILL_USED in one reply → all counted
// ───────────────────────────────────────────────────────────────────────
{
  const chatId = 4004;
  const reply =
    "<<SKILL_USED:skill-alpha|read frontmatter>>\n" +
    "<<SKILL_USED:skill-beta|followed testing guide>>\n" +
    "<<SKILL_USED:skill-gamma|used schema>>";
  await simulateObserver(chatId, reply);
  const usage = await usageStore.listAll(skillDir);
  const counts = {
    alpha: usage.skills["skill-alpha"].use_count,
    beta: usage.skills["skill-beta"].use_count,
    gamma: usage.skills["skill-gamma"].use_count,
  };
  // alpha was used in test 1 too → 2, beta/gamma first time → 1
  if (counts.alpha === 2 && counts.beta === 1 && counts.gamma === 1) {
    ok("4. multiple SKILL_USED → each name counted independently");
  } else {
    fail("4. multiple SKILL_USED → each name counted independently",
      JSON.stringify(counts));
  }
}

// ───────────────────────────────────────────────────────────────────────
// 5. Orphan SKILL_USED (agent hallucinates a name) → orphan entry created
// ───────────────────────────────────────────────────────────────────────
{
  await simulateObserver(
    5005,
    "<<SKILL_USED:skill-phantom|made it up>>",
  );
  const usage = await usageStore.listAll(skillDir);
  const phantom = usage.skills["skill-phantom"];
  if (phantom?.orphan === true && phantom.use_count === 1) {
    ok("5. orphan SKILL_USED creates orphan entry");
  } else {
    fail("5. orphan SKILL_USED creates orphan entry", JSON.stringify(phantom));
  }
}

// ───────────────────────────────────────────────────────────────────────
// 6. Full turn-cycle: set goal → 3 non-done replies → GOAL_DONE
// ───────────────────────────────────────────────────────────────────────
{
  const chatId = 6006;
  await goalStore.set(memoryDir, chatId, "write 4 files", { maxTurns: 10 });
  // 3 replies without GOAL_DONE, each should NOT change status
  for (let i = 0; i < 3; i++) {
    const out = await simulateObserver(chatId, `progress update ${i + 1}`);
    if (out.goalDone !== null) {
      fail(`6.${i} no-GOAL_DONE reply accidentally flags done`,
        JSON.stringify(out));
    }
    // Simulate caller doing incrementTurn between replies (AB-7 will do this).
    await goalStore.incrementTurn(memoryDir, chatId, `progress ${i + 1}`);
  }
  const beforeDone = await goalStore.get(memoryDir, chatId);
  if (beforeDone?.status !== "active" || beforeDone.turns_used !== 3) {
    fail("6a. after 3 turns: still active, turns_used=3",
      JSON.stringify(beforeDone));
  } else {
    ok("6a. after 3 turns: still active, turns_used=3");
  }
  // Final reply with GOAL_DONE
  await simulateObserver(
    chatId,
    "All 4 files created.\n<<GOAL_DONE:wrote 4 files as requested>>",
  );
  const afterDone = await goalStore.get(memoryDir, chatId);
  if (afterDone?.status === "done") {
    ok("6b. GOAL_DONE on active goal → done");
  } else {
    fail("6b. GOAL_DONE on active goal → done", JSON.stringify(afterDone));
  }
}

// ───────────────────────────────────────────────────────────────────────
// 7. Budget exhaustion (does not require GOAL_DONE)
// ───────────────────────────────────────────────────────────────────────
{
  const chatId = 7007;
  await goalStore.set(memoryDir, chatId, "budgeted task", { maxTurns: 3 });
  const r1 = await goalStore.incrementTurn(memoryDir, chatId);
  const r2 = await goalStore.incrementTurn(memoryDir, chatId);
  const r3 = await goalStore.incrementTurn(memoryDir, chatId);
  if (!r1.pausedByBudget && !r2.pausedByBudget && r3.pausedByBudget &&
      r3.state.status === "paused") {
    ok("7. budget exhaustion auto-pauses");
  } else {
    fail("7. budget exhaustion auto-pauses",
      JSON.stringify({ r1, r2, r3 }));
  }
}

// ───────────────────────────────────────────────────────────────────────
// 8. Pin flag survives restart (cross-smoke property)
// ───────────────────────────────────────────────────────────────────────
{
  await usageStore.setPinned(skillDir, "skill-alpha", true);
  // "restart" = fresh read
  const pin1 = await usageStore.isPinned(skillDir, "skill-alpha");
  // Another migrateFromDisk call (e.g. someone triggers /skillusage later)
  await usageStore.migrateFromDisk(skillDir);
  const pin2 = await usageStore.isPinned(skillDir, "skill-alpha");
  if (pin1 === true && pin2 === true) {
    ok("8. pin flag survives re-migration");
  } else {
    fail("8. pin flag survives re-migration", `pin1=${pin1} pin2=${pin2}`);
  }
}

// ───────────────────────────────────────────────────────────────────────
// Summary
// ───────────────────────────────────────────────────────────────────────
const failed = results.filter((r) => !r.pass);
console.log(
  `\n${results.length - failed.length}/${results.length} passed` +
    (failed.length ? ` — ${failed.length} failed` : ""),
);
if (failed.length > 0) process.exit(1);

