   103→        prefix = formatRecallBlock(hits) + prefix;
   104→      }
   105→    } catch (err) {
   106→      console.warn("[enrichment] memory recall failed:", err);
   107→    }
   108→  }
   109→
   110→  // 4. Index retrieval (PageIndex tree-based document chunks)
   111→  if (isIndexRetrievalReady() && !scope) {
   112→    try {
