// Handle taps on the inline help keyboard.
//   help:<name>   → show that command's description (or return to menu)
//   run:<name>    → execute the command (dispatched through COMMAND_HANDLERS)
bot.on("callback_query:data", async (ctx) => {
  if (!isAllowed(ctx)) {
    await ctx.answerCallbackQuery({ text: "未授權。" });
    return;
  }
  const data = ctx.callbackQuery.data;
  const [kind, name] = data.split(":", 2);

  if (kind === "help") {
    if (name === "_back") {
      await ctx.editMessageText(HELP_INTRO, {
        parse_mode: "HTML",
        reply_markup: buildHelpMenuKeyboard(),
      });
      await ctx.answerCallbackQuery();
      return;
    }
    const spec = COMMAND_SPECS.find((s) => s.name === name);
    if (!spec) {
      await ctx.answerCallbackQuery({ text: "未知的指令。" });
      return;
    }
    await ctx.editMessageText(renderCommandDetail(spec), {
      parse_mode: "HTML",
      reply_markup: buildCommandDetailKeyboard(spec),
    });
    await ctx.answerCallbackQuery();
    return;
  }

  if (kind === "run") {
    const spec = COMMAND_SPECS.find((s) => s.name === name);
    if (!spec) {
      await ctx.answerCallbackQuery({ text: "未知的指令。" });
      return;
    }
    if (spec.takesArg) {
      // Commands that strictly require an argument (e.g. /sendfile <path>)
      // can't be run from a button; hint the user to type it.
      await ctx.answerCallbackQuery({ text: "需要參數，請直接輸入指令。" });
      await ctx.reply(`請直接輸入 ${spec.usage} 來執行。`);
      return;
    }
    const handler = COMMAND_HANDLERS[spec.name];
    if (!handler) {
      await ctx.answerCallbackQuery({ text: "此指令尚未支援按鈕執行。" });
      return;
    }
    await ctx.answerCallbackQuery({ text: `執行 ${spec.usage} 中…` });
    try {
      await handler(ctx);
    } catch (err) {
      await ctx.reply(`執行失敗：${(err as Error).message}`);
    }
    return;
  }

  if (kind === "IL") {
    await handleIntelCallback(ctx, data);
    return;
  }

  if (kind === "SS") {
    await handleSkillSearchCallback(ctx, data);
    return;
  }

  if (kind === "MOAPLAN") {
    // MoA plan confirm keyboard (SPEC-moa-provider Phase 2 W16).
    const chatId = ctx.chat?.id;
    if (chatId === undefined) return;
    const action = name; // exec | edit | cancel
    const pending = getPendingPlan(chatId);
    try {
      await ctx.editMessageReplyMarkup({ reply_markup: undefined });
    } catch { /* keyboard already gone */ }
    if (!pending || pending.status === "executing") {
      await ctx.answerCallbackQuery({ text: pending ? "計畫已在執行中。" : "沒有待確認的計畫（可能已過期）。" });
      return;
    }
    if (action === "cancel") {
      clearPendingPlan(chatId);
      await ctx.answerCallbackQuery({ text: "已取消。" });
      await ctx.reply("❌ MoA 計畫已取消。").catch(() => {});
      return;
    }
    if (action === "edit") {
      pending.status = "awaiting-edit";
      await ctx.answerCallbackQuery({ text: "請輸入修改意見" });
      await ctx.reply("✏️ 請直接回覆修改意見（例如「把 2 和 3 合在一起」「加一步做測試」），我會重新規劃。").catch(() => {});
      return;
    }
    if (action === "exec") {
      await ctx.answerCallbackQuery({ text: "開始執行" });
      const userId = ctx.from?.id;
      const session = await sessions.get(chatId, userId);
      // Fire-and-forget: batches can run for many minutes.
      void executeMoaPlan(chatId, pending, {
        sendMessage: (cid, text) => bot.api.sendMessage(cid, text),
        injectMeta: (prompt) => runPrompt(ctx, session, prompt, { kind: "meta" }),
        userId,
      }).catch((err) => {
        console.error(`[chat ${chatId}] MoA plan execution failed:`, err);
        bot.api.sendMessage(chatId, `❌ MoA 計畫執行失敗：${(err as Error).message.slice(0, 300)}`).catch(() => {});
      });
      return;
    }
    await ctx.answerCallbackQuery({ text: "未知的動作。" });
    return;
  }

  if (kind === "DT") {
    // Dream todo：報告按鈕點擊 → 把 STATE.md High Priority 丟給主 session
    await handleDreamTodoCallback(ctx);
    return;
  }

  if (kind === "sess") {
    // /session 多 session 管理：sess:sw:<id>（切換）| sess:new（新對話）
    await handleSessionCallback(ctx, data);
    return;
  }

  if (kind === "A") {
    // ASK callback: data is `A:{question_id}:{key}`. split(":", 2) above
    // only gave us the first two fields, so re-split here to get the key.
    const parts = data.split(":");
    const questionId = parts[1] || "";
    const key = parts.slice(2).join(":"); // tolerate accidental ':' in key (shouldn't happen given ASK_KEY_RE)
    if (!questionId || !key) {
      await ctx.answerCallbackQuery({ text: "無效的選擇。" });
      return;
    }
    const msgId = ctx.callbackQuery.message?.message_id;
    const entries = msgId !== undefined ? askRegistry.get(msgId) : undefined;
    const entry = entries?.find((e) => e.questionId === questionId);
    const opt = entry?.options.find((o) => o.key === key);
    const label = opt?.label ?? key; // fallback to key if registry lost (e.g. after restart)

    // Strip the inline keyboard so the same buttons can't be re-tapped, but do
    // NOT rewrite the message content. Rewriting clobbered the original text —
    // and wiped it entirely when the message carried no plain `.text` (e.g. a
    // caption / rich-rendered message), which is the bug being fixed here. The
    // choice is surfaced via the callback toast and handled in a SEPARATE
    // follow-up message below (the runPrompt reply / wizard's ctx.reply), so
    // the message the user tapped stays intact.
    try {
      await ctx.editMessageReplyMarkup({ reply_markup: undefined });
    } catch (err) {
      // "message is not modified" (keyboard already gone) is harmless.
      console.warn(`[ASK] strip keyboard failed:`, (err as Error).message);
    }
    if (msgId !== undefined) askRegistry.delete(msgId);

    await ctx.answerCallbackQuery({ text: `已選擇：${label}` });

    // Inject the choice as a new user turn. Session is looked up the same
    // way the message handler does — ctx.chat is present on callback_query.
    const chatId = ctx.chat?.id;
    if (chatId === undefined) return;

    // ─── /schedule wizard hooks ───────────────────────────────────────────
    // The schedule wizard uses ASK but does NOT want the choice forwarded to
    // the agent: selections drive bridge-local state transitions instead.
    if (questionId === "sched_kind") {
      await handleSchedKindChoice(ctx, chatId, key);
      return;
    }
    if (questionId.startsWith("sched_t_")) {
      await handleSchedTimeChoice(ctx, chatId, questionId, key);
      return;
    }

    let session: ChatSession;
    try {
      session = await sessions.get(chatId, ctx.from?.id);
    } catch (err) {
      await ctx.reply(`Failed to start Kiro agent: ${(err as Error).message}`);
      return;
    }
    // Record the choice in the follow-up reply itself (header), so the original
    // button message stays intact AND no extra message is needed.
    await runPrompt(ctx, session, `[ASK:${questionId}] ${key}`, {
      kind: "user",
      replyHeader: `我選擇了：${label}`,
    });
    return;
  }

  if (kind === "specialist") {
    if (!name || !isLocalSpecialist(name)) {
      await ctx.answerCallbackQuery({ text: "分身不存在。" });
      return;
    }
    const chatId = ctx.chat!.id;
    startProxy(chatId, name);
    await ctx.answerCallbackQuery({ text: `進入 ${name}` });
    await ctx.editMessageText(`🤖 已進入 *${name}* proxy 模式。\n打 /back 退出。`, { parse_mode: "Markdown" });
    return;
  }

  if (kind === "sched") {
    // Schedule management buttons. Two ops today:
    //   - `sched:rm:<id>` — delete a single schedule, re-render the list.
    //   - `sched:cancel`  — no-op escape hatch; just strips the inline
    //                       keyboard from the current message so a user
    //                       can dismiss all the 🗑 buttons without risking
    //                       a fat-finger tap.
    // Future subcommands (e.g. "run") can share this branch.
    //
    // Policy:
    //   - Silent toast on success/failure via answerCallbackQuery.
    //   - For `rm`, re-render the whole list by editing the original
    //     message so the removed row disappears; if the list is now
    //     empty, strip the keyboard and change the text to "目前沒有排程。".
    //   - For `cancel`, only edit reply_markup (keep the text) so the
    //     user still sees what schedules exist — they just can't tap any.
    //   - Permission: bridge is 1-on-1 today, but be defensive — reject
    //     `rm` when entry.userId !== ctx.from?.id. `cancel` skips the
    //     check because it's non-destructive.
    const parts = data.split(":");
    const op = parts[1];
    const id = parts.slice(2).join(":"); // tolerate ':' in id (shouldn't happen; uuid slice)
    if (op === "cancel") {
      // Dismiss-keyboard escape hatch. No permission check: the button only
      // strips reply_markup from the message the user is already looking at,
      // so at worst a different user in a (hypothetical) group chat hides
      // the keyboard from themselves. No schedule state changes.
      try {
        await ctx.editMessageReplyMarkup({ reply_markup: undefined });
      } catch (err) {
        // "message is not modified" is fine — keyboard was already gone.
        console.warn(
          `[sched] cancel clear-keyboard failed:`,
          (err as Error).message,
        );
      }
      await ctx.answerCallbackQuery({ text: "已取消,未刪除任何排程。" });
      return;
    }
    if (op !== "rm" || !id) {
      await ctx.answerCallbackQuery({ text: "未知的操作。" });
      return;
    }
    const entry = scheduleStore.get(id);
    if (!entry) {
      // Already gone — stale button (user double-tapped, or fired since the
      // list was rendered). Tell them, then try to redraw the list so the
      // phantom row disappears.
      await ctx.answerCallbackQuery({ text: "排程已不存在。" });
      const chatId = ctx.chat?.id;
      if (chatId !== undefined) {
        const { text, keyboard } = renderScheduleList(chatId);
        try {
          await ctx.editMessageText(text, {
            reply_markup: keyboard ?? { inline_keyboard: [] },
          });
        } catch (err) {
          // editMessageText throws "message is not modified" if nothing
          // changed — that's fine, nothing to do.
          console.warn(
            `[sched] redraw after stale rm failed:`,
            (err as Error).message,
          );
        }
      }
      return;
    }
    if (ctx.from?.id !== undefined && entry.userId !== ctx.from.id) {
      await ctx.answerCallbackQuery({ text: "這不是你的排程。" });
      return;
    }
    const chatId = ctx.chat?.id;
    if (chatId !== undefined && entry.chatId !== chatId) {
      // Button from another chat somehow reached here — refuse.
      await ctx.answerCallbackQuery({ text: "排程不屬於這個聊天室。" });
      return;
    }
    scheduler.disarm(id);
    await scheduleStore.remove(id);
    await ctx.answerCallbackQuery({ text: `已移除 ${id}。` });

    // Redraw the list in place so the user sees the new state without
    // scrolling back to re-run /schedule list.
    if (chatId !== undefined) {
      const { text, keyboard } = renderScheduleList(chatId);
      try {
        await ctx.editMessageText(text, {
          reply_markup: keyboard ?? { inline_keyboard: [] },
        });
      } catch (err) {
        console.warn(
          `[sched] redraw after rm failed:`,
          (err as Error).message,
        );
      }
    }
    return;
  }

  if (kind === "SP") {
    // SKILL_PROPOSE callback: data is `SP:{name}:{yes|no}`.
    const parts = data.split(":");
    const skillName = parts[1] || "";
    const choice = parts[2] || "";
    const originalText = ctx.callbackQuery.message?.text ?? "";
    if (choice === "no") {
      try {
        await ctx.editMessageText(`${originalText}\n\n→ 已略過`);
      } catch { /* ignore */ }
      await ctx.answerCallbackQuery({ text: "已略過" });
      return;
    }
    if (choice === "yes") {
      try {
        await ctx.editMessageText(`${originalText}\n\n→ 開始萃取 skill…`);
      } catch { /* ignore */ }
      await ctx.answerCallbackQuery({ text: "開始萃取…" });
      const chatId = ctx.chat?.id;
      if (chatId === undefined) return;
      let session: ChatSession;
      try {
        session = await sessions.get(chatId, ctx.from?.id);
      } catch (err) {
        await ctx.reply(`Failed to start agent: ${(err as Error).message}`);
        return;
      }
      const skillDir = detectSkillDir();
      const prompt =
        `[系統] 使用者確認要把「${skillName}」寫成 skill。\n` +
        `請依照 memory-to-skill 和 writing-skills 的規範，在 ${skillDir}/ms-${skillName}/ 建立 SKILL.md。\n\n` +
        `規則：\n` +
        `- 先讀 ${skillDir}/writing-skills/SKILL.md 確認格式規範\n` +
        `- 檢查 ${skillDir}/ 是否已有同名或高度重疊的 skill，有就 append/rewrite\n` +
        `- YAML frontmatter 的 description 用「Use when…」開頭\n` +
        `- 內容來自本次對話中的經驗/模式\n` +
        `- 完成後 remember() 記錄新 skill 已建立`;
      await runPrompt(ctx, session, prompt, { kind: "meta" });
      return;
    }
    await ctx.answerCallbackQuery();
    return;
  }

  await ctx.answerCallbackQuery();
});

