// double-deletes and TOCTOU (someone appending/removing facts between the
// preview and the commit will invalidate the token).
//
// Deletion rewrites the master log in place and rebuilds all shards via
// rebuildShards(). We also append an audit entry to forget-log.md so a
// mistaken delete can be reconstructed by eye.

export interface ForgetMatch {
  /** Zero-based index in the master log (after filtering blank lines). */
  index: number;
  /** Full raw line including "- [ts] " prefix. */
  line: string;
  /** Fact text with "- [ts] " prefix stripped. */
  text: string;
}

/** Path of the shared audit log for forget operations. */
export function forgetLogFile(): string {
  return path.join(resolveMemoryDir(), "forget-log.md");
}

function readMasterLines(userId: number | string): string[] {
  const file = masterFactsFile(userId);
  try {
    const raw = readFileSync(file, "utf8");
    return raw
      .split(/\r?\n/)
      .map((l) => l.replace(/\s+$/, ""))
      .filter((l) => l.trim().length > 0);
  } catch {
    return [];
  }
}

/**
 * Compute a short deterministic token for a list of matched lines. Uses
 * SHA-1 of the sorted lines + count so the token is stable regardless of
 * iteration order but invalidates the moment the master log changes.
 */
export function computeForgetToken(matches: ForgetMatch[]): string {
  const h = createHash("sha1");
  const sorted = matches.map((m) => m.line).slice().sort();
  for (const l of sorted) {
    h.update(l);
    h.update("\n");
  }
  const hash8 = h.digest("hex").slice(0, 8);
  return `forget-${hash8}-${matches.length}`;
}

/**
 * Scan the master log and return every line whose stripped fact text
 * contains `query` (case-insensitive). Caller gets the exact lines and a
 * recomputable confirmation token.
 */
export function forgetMatch(
  userId: number | string,
  query: string
): { matches: ForgetMatch[]; token: string } {
  const q = (query ?? "").trim().toLowerCase();
  if (!q) return { matches: [], token: "forget-empty-0" };
  const lines = readMasterLines(userId);
  const matches: ForgetMatch[] = [];
  for (let i = 0; i < lines.length; i++) {
    const text = stripFactPrefix(lines[i]);
    if (text.toLowerCase().includes(q)) {
      matches.push({ index: i, line: lines[i], text });
    }
  }
  return { matches, token: computeForgetToken(matches) };
}

/**
 * Scan wiki/ directory for references to fact IDs. Returns a map of
 * factId → list of wiki files that reference it.
 */
export function checkWikiReferences(factIds: string[]): Record<string, string[]> {
  if (factIds.length === 0) return {};
  const wikiDir = path.join(resolveMemoryDir(), "wiki");
  if (!existsSync(wikiDir)) return {};
  const refs: Record<string, string[]> = {};
  const scan = (dir: string) => {
    for (const entry of readdirSync(dir, { withFileTypes: true })) {
      const full = path.join(dir, entry.name);
      if (entry.isDirectory()) { scan(full); continue; }
      if (!entry.name.endsWith(".md")) continue;
      const content = readFileSync(full, "utf8");
      for (const id of factIds) {
        if (content.includes(`f_${id}`)) {
          (refs[id] ??= []).push(path.relative(wikiDir, full).replace(/\\/g, "/"));
        }
      }
    }
  };
  scan(wikiDir);
  return refs;
}

/**
 * Delete every master-log line that matches `query` (case-insensitive
 * substring on the stripped fact text), then rebuild all shards. Returns
 * the deleted lines + fresh per-topic counts.
 *
 * If `expectedToken` is provided it must equal computeForgetToken(current
 * matches) — otherwise the call throws and nothing is written. This lets
 * the MCP tool implement a two-phase confirm without server-side state.
 */
export function forgetCommit(opts: {
  userId: number | string;
  query: string;
  expectedToken?: string;
}): {
  deleted: ForgetMatch[];
  wikiProtected: { match: ForgetMatch; referencedBy: string[] }[];
  remaining: number;
  shardSummary: { total: number; perTopic: Record<string, number> };
} {
  const { userId, query, expectedToken } = opts;
  const { matches, token } = forgetMatch(userId, query);
  if (matches.length === 0) {
    throw new Error(`no facts match query: ${JSON.stringify(query)}`);
  }
  if (expectedToken && expectedToken.trim() !== token) {
    throw new Error(
      `confirm token mismatch (got=${expectedToken}, expected=${token}); ` +
        `the master log changed since you previewed — call forget without ` +
        `confirm to re-preview.`
    );
  }

  // Check wiki references — protect facts that are cited by wiki pages.
  const factIds = matches.map(m => extractFactId(m.line)).filter((id): id is string => !!id);
  const wikiRefs = checkWikiReferences(factIds);
  const wikiProtected: { match: ForgetMatch; referencedBy: string[] }[] = [];
  const deletable: ForgetMatch[] = [];
  for (const m of matches) {
    const id = extractFactId(m.line);
    if (id && wikiRefs[id]?.length) {
      wikiProtected.push({ match: m, referencedBy: wikiRefs[id] });
    } else {
      deletable.push(m);
    }
  }

  // Rewrite master log with deletable indices stripped (wiki-protected kept).
  const master = masterFactsFile(userId);
  const allLines = readMasterLines(userId);
  const dropIdx = new Set(deletable.map((m) => m.index));
  const kept = allLines.filter((_, i) => !dropIdx.has(i));

  // Safety gate 1: never write an empty file if the original had content.
  if (kept.length === 0 && allLines.length > 0) {
    throw new Error(
      `[forgetCommit] refuse to empty the master log ` +
        `(${allLines.length} lines would all be deleted). ` +
        `This is almost certainly a bug — aborting.`
    );
  }

  // Safety gate 2: refuse to delete >50% of facts in a single operation.
  if (allLines.length > 0 && deletable.length > allLines.length * 0.5) {
    throw new Error(
      `[forgetCommit] refuse to delete ${deletable.length}/${allLines.length} facts ` +
        `(exceeds 50% threshold). Use smaller, more specific queries.`
    );
  }

  // Safety: backup master log before rewrite.
  try {
    copyFileSync(master, `${master}.bak.${Date.now()}`);

