// 一次性腳本：套用 2026-07-07 dream factlint 的刪除候選（26 條，重複那條已不在 master）。
// 語意完全照 mcp-memory.ts 的 forget tool：forgetCommit（含 wiki-protection、
// master 備份、shard rebuild、forget-log audit）+ deleteFact（SQLite index 同步）。
// 用後即刪。
import { fileURLToPath } from "node:url";
import path from "node:path";
import { readFileSync } from "node:fs";

process.env.TELEGRAM_BOT_TOKEN ||= "dummy"; // config.ts requires it

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const fs = await import(path.join("file:///", __dirname, "..", "dist", "facts-store.js").replace(/\\/g, "/"));
const db = await import(path.join("file:///", __dirname, "..", "dist", "memory-db.js").replace(/\\/g, "/"));

const uid = 509424983;
const masterFile = "G:/AI/AIMemory/facts-509424983.md";
const dryRun = process.argv.includes("--dry-run");

const ids = [
  // 過時 7
  "f_75638b", "f_86bdbb", "f_20ed42", "f_f67f15", "f_539667", "f_12d648", "f_a479e6",
  // 瑣碎 6
  "f_f578ad", "f_76faa7", "f_c8aeb0", "f_45e860", "f_f98bd7", "f_cb10bc",
  // 冗餘 13
  "f_456de2", "f_645ea3", "f_046ffa", "f_bafa71", "f_bef432",
  "f_89a745", "f_46f6e0", "f_94500e", "f_e9bd6a",
  "f_0a8153", "f_411e3f", "f_6d4701", "f_36e49d",
];

const masterLines = readFileSync(masterFile, "utf8").split(/\r?\n/).filter((l) => l.trim());
const byId = new Map();
for (const line of masterLines) {
  const id = fs.extractFactId(line);
  if (id) byId.set(`f_${id}`, line);
}

let deleted = 0, protectedN = 0, missing = 0, ambiguous = 0;
for (const id of ids) {
  const line = byId.get(id);
  if (!line) { console.log(`[MISSING] ${id} — 不在 master，跳過`); missing++; continue; }
  const text = fs.stripFactPrefix(line);
  const { matches } = fs.forgetMatch(uid, text);
  const exact = matches.filter((m) => fs.extractFactId(m.line) === id.replace(/^f_/, "") || m.line === line);
  if (matches.length !== 1) {
    console.log(`[AMBIGUOUS] ${id} — query 命中 ${matches.length} 行，跳過待手動`);
    ambiguous++; continue;
  }
  if (dryRun) { console.log(`[DRY] ${id} — ${text.slice(0, 60)}...`); continue; }
  const result = fs.forgetCommit({ userId: uid, query: text });
  for (const d of result.deleted) {
    db.deleteFact(d.text);
    console.log(`[DELETED] ${id} — ${d.text.slice(0, 60)}...`);
    deleted++;
  }
  for (const p of result.wikiProtected) {
    console.log(`[WIKI-PROTECTED] ${id} — ${p.referencedBy.join(", ")}`);
    protectedN++;
  }
}
console.log(`\n=== 套用結果：deleted=${deleted} wiki-protected=${protectedN} missing=${missing} ambiguous=${ambiguous} / ${ids.length}`);
const after = readFileSync(masterFile, "utf8").split(/\r?\n/).filter((l) => l.trim()).length;
console.log(`master 現有 ${after} 條`);

