/**
 * Memory-related command handlers.
 * Extracted from index.ts (P1 split).
 */
import { Context, InlineKeyboard } from "grammy";
import { readFileSync } from "node:fs";
import { config } from "../config.js";
import { appendFact, loadFacts, getFactsPath, writeFacts, listFacts } from "../memory.js";
import { detectAllShardDuplicates, suggestFactMerges } from "../local-llm.js";
import { listTopicShards } from "../facts-store.js";
import { getHitStats, computeRepoHealth } from "../hit-log.js";
import { runSpecialistReview, formatReviewReport, applyExpansions } from "../specialist-review.js";
import { isLocalSpecialist, getSpecialists } from "../specialist.js";
import { analyzeForSpecialist, generateSpecialistConfig } from "../specialist-create.js";
import { getRippleStatus, clearProcessedRipples } from "../ingest-ripple.js";
import { getPendingCandidates, markCandidatesProcessed } from "../query-auto-save.js";
import { deps } from "./deps.js";

const MEMORY_DIR = config.memoryDir;

export async function handleRemember(ctx: Context): Promise<void> {
  const { isAllowed, sessions, extractFromSession } = deps();
  if (!isAllowed(ctx)) return;
  const uid = ctx.from?.id;
  if (!uid) return;
  const text = typeof ctx.match === "string" ? ctx.match.trim() : "";
  if (!text) {
    const chatId = ctx.chat!.id;
    const session = sessions.peek(chatId);
    if (!session || session.history.length === 0) {
      await ctx.reply("No session history to extract. Usage: /remember <fact>");
      return;
    }
    const notice = await ctx.reply("🔍 Extracting facts from this session…");
    const added = await extractFromSession(session);
    await ctx.api.editMessageText(chatId, notice.message_id,
      added > 0
        ? `✅ Added ${added} new fact(s) to memory.`
        : "No new facts to remember.");
    return;
  }
  try {
    await appendFact(uid, text);
    await ctx.reply("✅ Remembered. (Applies to new sessions; /reset to apply now.)");
  } catch (err) {
    await ctx.reply(`Failed: ${(err as Error).message}`);
  }
}

export async function handleMemory(ctx: Context): Promise<void> {
  const { isAllowed } = deps();
  if (!isAllowed(ctx)) return;
  const uid = ctx.from?.id;
  if (!uid) return;
  const facts = await loadFacts(uid);
  if (!facts) {
    await ctx.reply(`(no memory yet)\nFile: ${getFactsPath(uid)}`);
    return;
  }
  const body = `📒 Memory (${getFactsPath(uid)}):\n\n${facts}`;
  await ctx.reply(body.length > 3900 ? body.slice(0, 3900) + "\n…(truncated)" : body);
}

export async function handleSummary(ctx: Context): Promise<void> {
  const { isAllowed, sessions, parseFactsJson } = deps();
  if (!isAllowed(ctx)) return;
  const uid = ctx.from?.id;
  if (!uid) return;
  const chatId = ctx.chat!.id;
  const existing = await loadFacts(uid);
  if (!existing) {
    await ctx.reply("No memory to summarize.");
    return;
  }
  let session;
  try {
    session = await sessions.get(chatId, uid);
  } catch (err) {
    await ctx.reply(`Failed to start agent: ${(err as Error).message}`);
    return;
  }

  if (session.inflight) {
    await ctx.reply(
      "⏳ 上一個回合還在進行中，無法同時跑 /summary。請等它結束，或先 /cancel。",
    );
    return;
  }

  const notice = await ctx.reply("🧹 Summarizing memory…");
  const prompt =
    "以下是一份長期累積的使用者事實清單。請整理：\n" +
    "1. 合併重複項（同一件事只留一條最完整的描述）。\n" +
    "2. 解決矛盾項（新的優先於舊的，只保留最新狀態）。\n" +
    "3. 不要主動刪除仍然有效的事實——即使看起來瑣碎，只要不是明確過時或重複就保留。\n" +
    "只輸出一個 JSON array，每個元素為一條簡短的繁體中文字串，不要任何前後說明文字、不要 code fence。\n\n" +
    "FACTS:\n" + existing;

  sessions.resetTurn(session);
  session.inflight = true;
  try {
    await session.client.prompt(prompt);
  } catch (err) {
    await ctx.api.editMessageText(chatId, notice.message_id,
      `Summary failed: ${(err as Error).message}`);
    return;
  } finally {
    session.inflight = false;
    sessions.clearInactivityTimer(session);
  }
  const facts = parseFactsJson(session.buffer);
  if (facts.length === 0) {
    await ctx.api.editMessageText(chatId, notice.message_id,
      "Summary produced no facts; memory left unchanged.");
    return;
  }
  await writeFacts(uid, facts);
  const preview = facts.slice(0, 10).map((f) => `• ${f}`).join("\n");
  await ctx.api.editMessageText(chatId, notice.message_id,
    `Memory condensed to ${facts.length} fact(s):\n\n${preview}` +
    (facts.length > 10 ? `\n…(${facts.length - 10} more)` : ""));
}


// ─── /memorytoskill ─────────────────────────────────────────────────────────

const MEMORY_TO_SKILL_PROMPT =
  "請使用 `memory-to-skill` skill 執行以下流程：\n" +
  "1. 掃描 `F:/AI/AIMemory/sessions/` 下所有 session 檔，識別可重用的技術模式。\n" +
  "2. 對每個候選，先比對 `~/.kiro/skills/` 下已安裝的 `ms-*` skill（讀各 SKILL.md 的 frontmatter）。\n" +
  "3. 依 skill 規則決定：新建 `ms-<name>/SKILL.md`、append 到既有 skill、或 rewrite 過時段落。\n" +
  "4. 處理完後把對應的 session 檔搬到 `F:/AI/AIMemory/oldSessions/`。\n" +
  "5. 對於頻率偵測候選中尚未成熟（出現次數不夠多或模式不夠明確）的項目，追加到 `${MEMORY_DIR}/wiki/tasks/skill-candidates.md`（格式：checkbox list，帶 pattern、count、代表性 message）。\n" +
  "6. 掃描 session 中的決策點：找到含「因為」「because」「排除」「rejected」「選了」「chose」的段落，將有 rationale 的決策用 remember() 存為 fact（格式：「因為 X 所以選 Y（排除 Z 因為 W）」）。跳過已存在的重複 fact。\n" +
  "7. 完成後回報：新建了哪些、更新了哪些、搬移了哪些檔、追蹤了哪些候選、抽取了幾條 rationale fact。\n" +
  "請嚴格依 skill 的門檻篩選候選，寧可少寫一個，也不要濫建。";

export async function handleMemoryToSkill(ctx: Context): Promise<void> {
  const { isAllowed, sessions, runPrompt } = deps();
  if (!isAllowed(ctx)) return;
  const chatId = ctx.chat!.id;
  let session;
  try {
    session = await sessions.get(chatId, ctx.from?.id);
  } catch (err) {
    await ctx.reply(
      `Failed to start Kiro agent: ${(err as Error).message}\n` +
        `Check that 'kiro-cli' is installed and on PATH.`
    );
    return;
  }
  const { suggestSkills, getCandidatePromotions } = await import("../skill-suggest.js");
  const candidates = suggestSkills();
  const promotions = getCandidatePromotions();
  let prompt = MEMORY_TO_SKILL_PROMPT;
  if (candidates.length > 0) {
    const candidateBlock = candidates
      .map(c => `- "${c.pattern}" (${c.count} sessions): ${c.examples[0] ?? ""}`)
      .join("\n");
    prompt +=
      "\n\n[頻率偵測候選 — 以下 pattern 在近 7 天 ≥3 個 session 重複出現且無對應 skill，請優先評估]\n" +
      candidateBlock +
      "\n[End 候選]";
  }
  if (promotions.length > 0) {
    const promotionBlock = promotions
      .map(p => `- ${p.isGlobal ? "[GLOBAL] " : ""}${p.text} (出現 ${p.occurrences} 次, 首見 ${p.firstSeen})`)
      .join("\n");
    prompt +=
      "\n\n[升格候選 — 以下 learning 已存在 ≥7 天且重複出現 ≥2 次，符合升格為 skill 的條件]\n" +
      promotionBlock +
      "\n指引：\n" +
      "- 評估每條候選是否真的值得成為正式 skill（跨專案可重用？還是只是個人偏好？）\n" +
      "- 值得升格的 → 用 <<SKILL_PROPOSE:name|reason>> 提議，reason 附計數佐證\n" +
      "- 兩條候選互相矛盾 → 都保留，加條件標註（何時用 A 何時用 B）\n" +
      "- 不值得升格的 → 跳過不處理（留在候選檔不刪）\n" +
      "[End 升格候選]";
  }
  await runPrompt(ctx, session, prompt, { kind: "meta" });
}

// ─── /topicreview ───────────────────────────────────────────────────────────

const TOPIC_REVIEW_PROMPT =
  "請執行 topic review：\n" +
  "1. 先呼叫 `propose_topics` MCP tool 取得目前完整的 facts 清單、現有 topics.json、以及各 shard 筆數。\n" +
  "2. 依以下原則重新設計 topic 分類：\n" +
  "   - topic 名稱用 kebab-case、≤40 字，first-match-wins（把細分類排在廣義分類前面）\n" +
  "   - 每個 topic 的 keywords 為小寫 substring（會對 fact 全文小寫後 includes 比對）\n" +
  "   - 盡量讓 'misc' 只剩零星幾則；但若某類別 <5 則不值得獨立，就讓它落到相近的 topic 或 misc\n" +
  "   - 合併語意重疊的 topic；拆分過於包山包海的 topic\n" +
  "   - topic 總數 ≤ 50（MEMORY_MAX_TOPICS 可調整）\n" +
  "3. 然後呼叫 `apply_topics` 直接套用新的 topics 陣列（不要 dry-run、不要問我確認，一次到位）。\n" +
  "4. 最後回報：新增/刪除/合併了哪些 topic、各 topic 新筆數、topics.bak 檔路徑。\n" +
  "整個過程用繁體中文摘要，不要貼完整 JSON。";

export async function handleTopicReview(ctx: Context): Promise<void> {
  const { isAllowed, sessions, runPrompt } = deps();
  if (!isAllowed(ctx)) return;
  const chatId = ctx.chat!.id;
  let session;
  try {
    session = await sessions.get(chatId, ctx.from?.id);
  } catch (err) {
    await ctx.reply(
      `Failed to start Kiro agent: ${(err as Error).message}\n` +
        `Check that 'kiro-cli' is installed and on PATH.`
    );
    return;
  }
  await runPrompt(ctx, session, TOPIC_REVIEW_PROMPT, { kind: "meta" });
}


// ─── /refreshrouting ────────────────────────────────────────────────────────

const REFRESH_ROUTING_PROMPT =
  "請執行 NotebookLM routing table 刷新（v2 repr 格式）：\n" +
  `1. 依 \`ms-notebooklm-routing-builder\` skill 的流程：先 \`notebook_list\` 拿現況，讀既有 \`${MEMORY_DIR}/config/notebooklm-routing.json\`（如存在）做 diff。\n` +
  `2. 寫新檔前先備份到 \`${MEMORY_DIR}/config/notebooklm-routing.bak.<ts>.json\`（保留最近 5 份，舊的清掉）。\n` +
  "3. 對每本 notebook 跑 `notebook_query` 產出 repr 文字（一段 100-300 字的主題描述，涵蓋核心術語、人名、專有名詞，供 embedding 向量化用）。\n" +
  "4. 合併規則：\n" +
  "   - 新 notebook → append 新 entry（notebook_id, title, repr, strategy: 'primary'）。\n" +
  "   - 既有 notebook → 只更新 repr / last_refreshed；strategy / strategy_notes / manual_overrides 絕不覆蓋。\n" +
  "   - 從 NotebookLM 消失的 notebook → 標 `\"removed\": true` 而非硬刪。\n" +
  "   - `multi_match_rules` 原樣保留，不碰。\n" +
  "5. 最後回報：新增/刪除/更新了哪些 notebook、repr 差異摘要、備份檔路徑。\n" +
  "整個過程用繁體中文摘要，不要貼完整 JSON。";

export async function handleRefreshRouting(ctx: Context): Promise<void> {
  const { isAllowed, sessions, runPrompt } = deps();
  if (!isAllowed(ctx)) return;
  const chatId = ctx.chat!.id;
  let session;
  try {
    session = await sessions.get(chatId, ctx.from?.id);
  } catch (err) {
    await ctx.reply(
      `Failed to start Kiro agent: ${(err as Error).message}\n` +
        `Check that 'kiro-cli' is installed and on PATH.`
    );
    return;
  }
  await runPrompt(ctx, session, REFRESH_ROUTING_PROMPT, { kind: "meta" });
}

// ─── /wikisync ──────────────────────────────────────────────────────────────

const WIKISYNC_PROMPT =
  `請執行 wiki sync（依 ms-wiki-knowledge-base skill 的 wikisync 邏輯）：\n` +
  `0. 若 ${MEMORY_DIR}/wiki/ 目錄不存在，先建立 wiki/、wiki/concepts/、wiki/references/、wiki/lessons/、wiki/queries/ 並寫一份空 index.md（參考 SCHEMA.md 格式）。\n` +
  `1. 讀 ${MEMORY_DIR}/wiki/index.md 取得現有 wiki 頁面列表。\n` +
  `2. 呼叫 list_facts({ query: '', tail: 0 }) 或讀 topics.json 取得所有 topic 名稱。\n` +
  `3. 對每個 topic shard（≥5 facts 且 index.md 中無對應 wiki page）：\n` +
  `   - 呼叫 list_facts({ query: '<topic>' }) 讀 shard 內容\n` +
  `   - 產出一頁 ${MEMORY_DIR}/wiki/concepts/<topic>.md（結構化段落，不是 flat list）\n` +
  `   - 遵循 SCHEMA.md 的 frontmatter 格式、至少 1 個 [[wikilink]]、≤200 行\n` +
  `   - frontmatter sources 欄位記錄來源 fact IDs（格式：sources: [f_xxxxxx, f_yyyyyy, ...]），從 shard 行首 [f_xxxxxx] 提取\n` +
  `   - 若產出 type=lesson 頁面，frontmatter 加 why 欄位：從 shard facts 中找含「因為」「because」的句子，摘要成一句根因\n` +
  `4. 對已有 wiki page 但 shard 有明顯新內容的：更新頁面 + bump updated 日期 + 追加新 fact IDs 到 sources。\n` +
  `5. 每次新增/更新頁面後同步更新 index.md（加一行 wikilink + 摘要、更新 Total pages）。\n` +
  `6. 完成後回報：新增了哪些頁面、更新了哪些、跳過了哪些（含原因）。\n` +
  `用繁體中文撰寫所有 wiki 頁面。一次最多處理 5 個 topic，避免 context 爆炸。\n` +
  `回覆末尾加上：<<SKILL_USED:ms-wiki-knowledge-base|wikisync 步驟>>`;

/**
 * 組出這一輪 wikisync 的完整 prompt：基底 WIKISYNC_PROMPT + Ingest Ripple
 * 優先清單 + Query Auto-save 候選。回傳注入的 topic/slug 清單，供完成後
 * 樂觀清理（部分失敗會由下次 ripple 累積重新標記）。
 */
function buildWikiSyncPrompt(): { prompt: string; rippleTopics: string[]; candidateSlugs: string[] } {
  let prompt = WIKISYNC_PROMPT;
  const rippleTopics: string[] = [];
  const candidateSlugs: string[] = [];

  try {
    const ripple = getRippleStatus();
    const top = ripple.pagesNeedingUpdate.slice(0, 5);
    if (top.length) {
      rippleTopics.push(...top.map((p) => p.topic));
      prompt +=
        `\n\n【Ingest Ripple 優先清單】以下 wiki page 自上次同步後已累積新 facts，步驟 4 請優先處理：\n` +
        top.map((p) => `- wiki/${p.type}/${p.slug}.md（topic: ${p.topic}，${p.pendingCount} 條未同步）`).join("\n");
    }
  } catch (err) {
    console.warn("[wikisync] ripple status read failed:", err);
  }

  try {
    const candidates = getPendingCandidates().slice(0, 5);
    if (candidates.length) {
      candidateSlugs.push(...candidates.map((c) => c.slug));
      prompt +=
        `\n\n【Query Auto-save 候選】以下回覆被自動判定值得存為 query page，` +
        `請各產出一頁 wiki/queries/<slug>.md（frontmatter type: query，規則同上）：\n` +
        candidates.map((c) => `- ${c.slug} — ${c.summary}`).join("\n");
    }
  } catch (err) {
    console.warn("[wikisync] auto-save candidates read failed:", err);
  }

  return { prompt, rippleTopics, candidateSlugs };
}

export async function handleWikiSync(ctx: Context): Promise<void> {
  const { isAllowed, sessions, runPrompt } = deps();
  if (!isAllowed(ctx)) return;
  const chatId = ctx.chat!.id;
  let session;
  try {
    session = await sessions.get(chatId, ctx.from?.id);
  } catch (err) {
    await ctx.reply(
      `Failed to start Kiro agent: ${(err as Error).message}\n` +
        `Check that 'kiro-cli' is installed and on PATH.`,
    );
    return;
  }
  const { prompt, rippleTopics, candidateSlugs } = buildWikiSyncPrompt();
  await runPrompt(ctx, session, prompt, { kind: "meta" });
  // 樂觀清理：這輪已把清單交給 agent 處理，清掉標記避免下輪重複注入。
  // 若 agent 部分失敗，後續新 fact 寫入會重新累積 ripple 標記。
  if (rippleTopics.length) clearProcessedRipples(rippleTopics);
  if (candidateSlugs.length) markCandidatesProcessed(candidateSlugs);
}


