export async function handleFactLint(ctx: Context): Promise<void> {
  const { isAllowed, sessions, runPrompt } = deps();
  if (!isAllowed(ctx)) return;
  const chatId = ctx.chat!.id;
  let session;
  try {
    session = await sessions.get(chatId, ctx.from?.id);
  } catch (err) {
    await ctx.reply(
      `Failed to start Kiro agent: ${(err as Error).message}\n` +
        `Check that 'kiro-cli' is installed and on PATH.`,
    );
    return;
  }

  // Pre-scan ALL shards with local LLM for dedup hints (best-effort)
  let dedupHint = "";
  try {
    const userId = ctx.from?.id;
    if (userId) {
      const shardInfos = listTopicShards(userId);
      const shards = shardInfos.map(s => ({
        topic: s.topic,
        facts: readFileSync(s.file, "utf8").split(/\r?\n/).filter(l => l.trim()),
      }));
      const issues = await detectAllShardDuplicates(shards);
      if (issues.length > 0) {
        const lines = issues.map(
          iss => `  - [${iss.topic}] ${iss.type.toUpperCase()}: "${iss.factA.slice(0, 60)}" vs "${iss.factB.slice(0, 60)}" — ${iss.reason}`
        );
        dedupHint = `\n\n[Local LLM pre-scan detected ${issues.length} potential issue(s) across shards — verify and act on these first]\n${lines.join("\n")}\n`;
      }
    }
  } catch { /* Ollama unavailable — skip pre-scan */ }

  // Merge/upgrade suggestions from local LLM (optional)
  let mergeHint = "";
  try {
    const userId = ctx.from?.id;
    if (userId) {
      const shardInfos = listTopicShards(userId);
      const bigShards = shardInfos.filter(s => s.count >= 5);
      const allSuggestions: string[] = [];
      for (const s of bigShards.slice(0, 5)) {
        const facts = readFileSync(s.file, "utf8").split(/\r?\n/).filter(l => l.trim());
        const suggestions = await suggestFactMerges(s.topic, facts);
        for (const sg of suggestions) {
          allSuggestions.push(`  - [${s.topic}] 合併 #${sg.indices.join(",")} → "${sg.merged}"`);
        }
      }
      if (allSuggestions.length > 0) {
        mergeHint = `\n\n[升格建議 — Local LLM 建議以下 facts 可合併精煉（僅供參考，不自動執行）]\n${allSuggestions.join("\n")}\n`;
      }
    }
  } catch { /* Ollama unavailable — skip */ }

  // Hit log stats: zero-hit topics + repo health
  let hitHint = "";
  try {
    const userId = ctx.from?.id;
    if (userId) {
      const stats = await getHitStats(30);
      const shardInfos = listTopicShards(userId);
      const allTopics = shardInfos.map(s => s.topic);
      const zeroHit = allTopics.filter(t => !stats.has(`fact:${t}`));
      if (zeroHit.length > 0) {
        hitHint += `\n\n[零命中區 — 以下 topic shards 過去 30 天未被任何 embedding recall 命中]\n${zeroHit.map(t => `  - ${t}`).join("\n")}\n對這些 shard 的 facts 額外留意是否已過時或描述不夠好。\n`;
      }
      const health = computeRepoHealth(shardInfos);
      if (health.ratio > 3.0) {
        hitHint += `\n[⚠️ Repo 膨脹警告] total=${health.total}, actionable=${health.actionable}, ratio=${health.ratio.toFixed(1)} (>3.0)\n建議清理純記錄性 facts（不含指引語的）。\n`;
      }
    }
  } catch { /* hit-log not yet populated — skip */ }

  await runPrompt(ctx, session, FACTLINT_PROMPT + dedupHint + mergeHint + hitHint, { kind: "meta" });
}


