  } catch (err: any) {
    await ctx.api.editMessageText(chatId, notice.message_id, `❌ specialist-review 失敗：${err.message}`);
  }
}

// ─── /specialist ────────────────────────────────────────────────────────────

export async function handleSpecialist(ctx: Context): Promise<void> {
  const { isAllowed } = deps();
  if (!isAllowed(ctx)) return;
  const arg = (ctx.match as string | undefined)?.trim() ?? "";
  const parts = arg.split(/\s+/);

  // No arg → show inline keyboard to pick a specialist for proxy
  if (!arg || (parts[0] !== "create" && !isLocalSpecialist(arg))) {
    const specialists = getSpecialists();
    if (specialists.length === 0) {
      await ctx.reply("目前沒有可用的分身。用 /specialist create <name> 建立。");
      return;
    }
    const kb = new InlineKeyboard();
    for (const s of specialists) {
      kb.text(`🤖 ${s.name}`, `specialist:${s.name}`).row();
    }
    await ctx.reply("選擇分身進入 proxy：", { reply_markup: kb });
    return;
  }

  if (parts[0] !== "create" || !parts[1]) {
    await ctx.reply("用法：/specialist create <name>");
    return;
  }

  const name = parts[1].toLowerCase();
  const notice = await ctx.reply(`🤖 分析 specialist "${name}" 的 skill 組合…`);

  try {
    const analysis = await analyzeForSpecialist(name);
    const result = await generateSpecialistConfig(analysis);

    const lines = [
      `✅ Specialist "${name}" 配置已產生：`,
      ``,
      `📄 Agent config: \`${result.agentConfigPath}\``,
      `📄 Specialists: \`${result.specialistsJsonPath}\``,
      ``,
      `🧩 Skills (${result.skills.length}):`,
      ...result.skills.map((s) => `  • ${s}`),
      ``,
      `🔌 MCP servers: ${result.mcpServers.length ? result.mcpServers.join(", ") : "(none)"}`,
      ``,
      `🏷️ Related topics (${analysis.relevantTopics.length}):`,
      ...analysis.relevantTopics.slice(0, 10).map((t) => `  • ${t}`),
      ``,
      `⚠️ 需要 /restart 才會載入新配置。`,
    ];

    await ctx.api.editMessageText(ctx.chat!.id, notice.message_id, lines.join("\n"));
  } catch (err: any) {
    await ctx.api.editMessageText(
      ctx.chat!.id,
      notice.message_id,
      `❌ 失敗：${err.message}`,
    );
  }
}
